1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import { ArrowLeft, Download, ExternalLink, Network, FileClock } from 'lucide-svelte';
5		import { marked } from 'marked';
6		import DOMPurify from 'isomorphic-dompurify';
7		import { onMount } from 'svelte';
8		import { createClient } from '$lib/gql/client';
9		import { gql } from 'graphql-request';
10	
11		let { data }: { data: PageData } = $props();
12	
13		const ARTIFACT_BY_PATH_QUERY = gql`
14			query ArtifactsByPath($projectID: ID!, $search: String) {
15				artifacts(projectID: $projectID, search: $search) {
16					edges {
17						node {
18							id
19							path
20						}
21					}
22				}
23			}
24		`;
25	
26		const listHref = data.back ?? `/nodes/${data.nodeId}/projects/${data.projectId}/artifacts`;
27	
28		function stalenessBadge(staleness: string): { label: string; cls: string } {
29			switch (staleness) {
30				case 'fresh':
31					return {
32						label: 'fresh',
33						cls: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
34					};
35				case 'stale':
36					return {
37						label: 'stale',
38						cls: 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-400'
39					};
40				case 'missing':
41					return {
42						label: 'missing',
43						cls: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400'
44					};
45				default:
46					return {
47						label: staleness,
48						cls: 'bg-bg-surface text-fg-muted dark:bg-dark-bg-surface dark:text-dark-fg-muted'
49					};
50			}
51		}
52	
53		// Determine renderer type from mediaType
54		function rendererType(
55			mt: string
56		): 'markdown' | 'svg' | 'excalidraw' | 'image' | 'pdf' | 'binary' {
57			if (mt === 'text/markdown') return 'markdown';
58			if (mt === 'image/svg+xml') return 'svg';
59			if (mt === 'application/vnd.excalidraw+json') return 'excalidraw';
60			if (mt.startsWith('image/')) return 'image';
61			if (mt === 'application/pdf') return 'pdf';
62			return 'binary';
63		}
64	
65		// Rendered markdown HTML
66		const renderedMarkdown = $derived.by(() => {
67			if (!data.artifact?.content || rendererType(data.artifact.mediaType) !== 'markdown') return '';
68			const raw = marked.parse(data.artifact.content, { async: false }) as string;
69			return DOMPurify.sanitize(raw);
70		});
71	
72		// Sanitized SVG content
73		const sanitizedSvg = $derived.by(() => {
74			if (!data.artifact?.content || rendererType(data.artifact.mediaType) !== 'svg') return '';
75			return DOMPurify.sanitize(data.artifact.content, {
76				USE_PROFILES: { svg: true, svgFilters: true }
77			});
78		});
79	
80		// DDx frontmatter parsed as key/value pairs
81		const frontmatterEntries = $derived.by((): [string, string][] => {
82			if (!data.artifact?.ddxFrontmatter) return [];
83			try {
84				const fm = JSON.parse(data.artifact.ddxFrontmatter);
85				if (typeof fm !== 'object' || fm === null) return [];
86				return Object.entries(fm).map(([k, v]) => [
87					k,
88					typeof v === 'object' ? JSON.stringify(v) : String(v)
89				]);
90			} catch {
91				return [];
92			}
93		});
94	
95		// Offline detection for Excalidraw
96		let isOnline = $state(true);
97		onMount(() => {
98			isOnline = navigator.onLine;
99			const handleOnline = () => {
100				isOnline = true;
101			};
102			const handleOffline = () => {
103				isOnline = false;
104			};
105			window.addEventListener('online', handleOnline);
106			window.addEventListener('offline', handleOffline);
107			return () => {
108				window.removeEventListener('online', handleOnline);
109				window.removeEventListener('offline', handleOffline);
110			};
111		});
112	
113		// Resolve a relative href against the base directory of the current artifact.
114		function resolvePath(relativePath: string, baseDir: string): string {
115			if (relativePath.startsWith('/')) return relativePath.slice(1);
116			const parts = baseDir ? baseDir.split('/') : [];
117			for (const segment of relativePath.split('/')) {
118				if (segment === '..') parts.pop();
119				else if (segment !== '.') parts.push(segment);
120			}
121			return parts.join('/');
122		}
123	
124		// Process markdown links: external links get target="_blank"; relative intra-repo
125		// links are rewritten to href="#" with data-ddx-intra-path for client-side navigation.
126		function processMarkdownHtml(html: string): string {
127			const artifactPath = data.artifact?.path ?? '';
128			const baseDir = artifactPath.split('/').slice(0, -1).join('/');
129			return html.replace(/<a\s+href="([^"]+)"/g, (_match, href) => {
130				const isExternal = /^https?:\/\//.test(href) || href.startsWith('//');
131				if (isExternal) {
132					return `<a href="${href}" target="_blank" rel="noopener noreferrer"`;
133				}
134				const resolvedPath = resolvePath(href, baseDir);
135				return `<a href="#" data-ddx-intra-path="${resolvedPath}"`;
136			});
137		}
138	
139		const finalMarkdownHtml = $derived(processMarkdownHtml(renderedMarkdown));
140	
141		async function handleMarkdownClick(e: MouseEvent) {
142			const anchor = (e.target as Element).closest('a[data-ddx-intra-path]');
143			if (!anchor) return;
144			e.preventDefault();
145			const intraPath = anchor.getAttribute('data-ddx-intra-path');
146			if (!intraPath) return;
147			const client = createClient();
148			const result = await client.request<{
149				artifacts: { edges: { node: { id: string; path: string } }[] };
150			}>(ARTIFACT_BY_PATH_QUERY, { projectID: data.projectId, search: intraPath });
151			const match = result.artifacts.edges.find((edge) => edge.node.path === intraPath);
152			if (match) {
153				goto(
154					`/nodes/${data.nodeId}/projects/${data.projectId}/artifacts/${encodeURIComponent(match.node.id)}`
155				);
156			}
157		}
158	</script>
