57	// WorkerDispatch is the resolver for the workerDispatch field.
58	func (r *mutationResolver) WorkerDispatch(ctx context.Context, kind string, projectID string, args *string) (*WorkerDispatchResult, error) {
59		switch kind {
60		case "execute-loop":
61			if r.Actions == nil {
62				return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
63			}
64			return r.Actions.DispatchWorker(ctx, kind, r.projectRoot(projectID), args)
65		case "realign-specs", "run-checks":
66			return &WorkerDispatchResult{
67				ID:    "queued-worker-" + slug(kind),
68				State: queuedPlaceholderState,
69				Kind:  kind,
70			}, nil
71		default:
72			return nil, fmt.Errorf("unsupported worker kind %q", kind)
73		}
74	}
