76	// StartWorker is the resolver for the startWorker field.
77	//
78	// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
79	// project's .ddx/config.yaml drives default harness/profile/effort/label
80	// values when the GraphQL input leaves them unset. Input fields are layered
81	// onto config as CLIOverrides — when present they win over the on-disk
82	// values. The resolved values are forwarded to ActionDispatcher (and ultimately
83	// to runWorker, which re-loads config to drive the loop's durable knobs like
84	// review_max_retries / no_progress_cooldown / heartbeat_interval). This
85	// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
86	// shadowed the on-disk config.
87	func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
88		if r.Actions == nil {
89			return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
90		}
91		projectRoot := r.projectRoot(input.ProjectID)
92	
93		overrides := config.CLIOverrides{}
94		if input.Harness != nil {
95			overrides.Harness = strings.TrimSpace(*input.Harness)
96		}
97		if input.Profile != nil {
98			overrides.Profile = strings.TrimSpace(*input.Profile)
99		}
100		if input.Effort != nil {
101			overrides.Effort = strings.TrimSpace(*input.Effort)
102		}
103		rcfg, _ := config.LoadAndResolve(projectRoot, overrides)
104	
105		args := map[string]string{}
106		if v := rcfg.Harness(); v != "" {
107			args["harness"] = v
108		}
109		profile := rcfg.Profile()
110		if profile == "" {
111			profile = "smart"
112		}
113		args["profile"] = profile
114		effort := rcfg.Effort()
115		if effort == "" {
116			effort = "medium"
117		}
118		args["effort"] = effort
119		if input.LabelFilter != nil && strings.TrimSpace(*input.LabelFilter) != "" {
120			args["label_filter"] = strings.TrimSpace(*input.LabelFilter)
121		}
122		raw, err := json.Marshal(args)
123		if err != nil {
124			return nil, err
125		}
126		rawArgs := string(raw)
127		return r.Actions.DispatchWorker(ctx, "execute-loop", projectRoot, &rawArgs)
128	}
