138	// PluginDispatch is the resolver for the pluginDispatch field.
139	func (r *mutationResolver) PluginDispatch(ctx context.Context, name string, action string, scope string) (*PluginDispatchResult, error) {
140		name = strings.TrimSpace(name)
141		action = strings.ToLower(strings.TrimSpace(action))
142		scope = strings.ToLower(strings.TrimSpace(scope))
143		if name == "" {
144			return nil, fmt.Errorf("plugin name is required")
145		}
146		if scope != "project" {
147			return nil, fmt.Errorf("unsupported plugin scope %q", scope)
148		}
149	
150		if r.Actions == nil {
151			return nil, fmt.Errorf("plugin dispatcher is not configured")
152		}
153		result, err := r.Actions.DispatchPlugin(ctx, r.WorkingDir, name, action, scope)
154		if err != nil {
155			return nil, err
156		}
157		if err := writeJSONRecord(r.WorkingDir, "plugin-dispatches", result.ID, pluginDispatchRecord{
158			ID:        result.ID,
159			Name:      name,
160			Action:    action,
161			Scope:     scope,
162			State:     result.State,
163			CreatedAt: time.Now().UTC(),
164		}); err != nil {
165			return nil, err
166		}
167		return result, nil
168	}
