170	// ComparisonDispatch is the resolver for the comparisonDispatch field.
171	func (r *mutationResolver) ComparisonDispatch(ctx context.Context, arms []*ComparisonArmInput) (*ComparisonDispatchResult, error) {
172		if len(arms) == 0 {
173			return nil, fmt.Errorf("comparison requires at least one arm")
174		}
175		for i, arm := range arms {
176			if arm == nil {
177				return nil, fmt.Errorf("comparison arm %d is required", i)
178			}
179			arm.Model = strings.TrimSpace(arm.Model)
180			arm.Prompt = strings.TrimSpace(arm.Prompt)
181			if arm.Model == "" {
182				return nil, fmt.Errorf("comparison arm %d model is required", i)
183			}
184			if arm.Prompt == "" {
185				return nil, fmt.Errorf("comparison arm %d prompt is required", i)
186			}
187			if arm.Harness != nil {
188				trimmed := strings.TrimSpace(*arm.Harness)
189				arm.Harness = &trimmed
190			}
191			if arm.Provider != nil {
