315	// Returns zeros — not an error — for unknown or empty projects so the nav
316	// component can render without special-casing failures.
317	func (r *queryResolver) QueueAndWorkersSummary(ctx context.Context, projectID string) (*QueueAndWorkersSummary, error) {
318		out := &QueueAndWorkersSummary{}
319		// Only resolve ready beads when the projectID maps to a real project.
320		// Unknown IDs return zeros rather than falling back to WorkingDir so the
321		// indicator does not surface an unrelated project's queue depth.
322		if r.State != nil {
323			if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
324				store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
325				if ready, err := store.Ready(); err == nil {
326					out.ReadyBeads = len(ready)
327				}
328			}
329			workers := r.State.GetWorkersGraphQL(projectID)
330			out.TotalWorkers = len(workers)
331			for _, w := range workers {
332				if w != nil && w.State == "running" {
333					out.RunningWorkers++
