335			}
336		}
337		// Surface the optional workers.max_count cap so the UI can pre-emptively
338		// disable the `+ Add worker` affordance rather than relying on a server
339		// error from workerDispatch (ddx-b6cf025c review finding).
340		if cfg, err := config.LoadWithWorkingDir(r.projectRoot(projectID)); err == nil && cfg != nil && cfg.Workers != nil && cfg.Workers.MaxCount != nil {
341			v := *cfg.Workers.MaxCount
342			out.MaxCount = &v
343		}
344		return out, nil
345	}
