479	func DispatchPluginAction(workingDir string, name string, action string) (string, error) {
480		pluginActionMu.Lock()
481		defer pluginActionMu.Unlock()
482	
483		state, err := registry.LoadState()
484		if err != nil {
485			return "", fmt.Errorf("loading plugin state: %w", err)
486		}
487	
488		switch action {
489		case "install":
490			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
491				return "installed", nil
492			}
493			entry, err := installRegistryPlugin(workingDir, state, name)
494			if err != nil {
495				return "", err
496			}
497			if entry != nil && entry.VerifyFiles() {
498				return "installed", nil
499			}
500			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
501		case "update":
502			installed := state.FindInstalled(name)
503			if installed == nil {
504				return "", fmt.Errorf("plugin %q is not installed", name)
505			}
506			pkg, err := registry.BuiltinRegistry().Find(name)
507			if err != nil {
508				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
509			}
510			if installed.Version == pkg.Version && installed.VerifyFiles() {
511				return "installed", nil
512			}
513			entry, err := installRegistryPlugin(workingDir, state, name)
514			if err != nil {
515				return "", err
516			}
517			if entry != nil && entry.VerifyFiles() {
518				return "installed", nil
519			}
520			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
521		case "uninstall":
522			entry := state.FindInstalled(name)
523			if entry == nil {
524				return "", fmt.Errorf("plugin %q is not installed", name)
525			}
526			if err := registry.UninstallPackage(entry); err != nil {
527				return "", err
528			}
529			state.Remove(name)
530			if err := registry.SaveState(state); err != nil {
531				return "", fmt.Errorf("saving plugin state: %w", err)
532			}
533			return "uninstalled", nil
534		default:
535			return "", fmt.Errorf("unsupported plugin action %q", action)
536		}
537	}
538	
539	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
540		pkg, err := registry.BuiltinRegistry().Find(name)
541		if err != nil {
542			return nil, err
543		}
544	
545		origDir, _ := os.Getwd()
546		if workingDir != "" && origDir != workingDir {
547			if err := os.Chdir(workingDir); err != nil {
548				return nil, fmt.Errorf("entering project root: %w", err)
549			}
550			defer func() { _ = os.Chdir(origDir) }()
551		}
552	
553		entry, err := registry.InstallPackage(pkg, workingDir)
554		if err != nil {
555			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
556		}
557		state.AddOrUpdate(entry)
558		if err := registry.SaveState(state); err != nil {
559			return nil, fmt.Errorf("saving plugin state: %w", err)
560		}
561		return state.FindInstalled(name), nil
562	}
