613	func newDispatchID(prefix string, parts ...string) string {
614		segments := []string{slug(prefix)}
615		for _, part := range parts {
616			if s := slug(part); s != "" {
617				segments = append(segments, s)
618			}
619		}
620		segments = append(segments, randomHex(4))
621		return strings.Join(segments, "-")
622	}
623	
624	func randomHex(n int) string {
625		b := make([]byte, n)
626		if _, err := rand.Read(b); err != nil {
627			return time.Now().UTC().Format("20060102T150405.000000000")
628		}
629		return hex.EncodeToString(b)
630	}
