709	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, _ registry.InstalledEntry) {
710		if workingDir == "" {
711			return
712		}
713		root := filepath.Join(workingDir, ".ddx", "plugins", name)
714		if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
715			return
716		}
717		if info.DiskBytes == 0 {
718			info.DiskBytes = dirSize(root)
719		}
720		if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
721			if pkg.Version != "" {
722				info.Version = pkg.Version
723			}
724			if pkg.Description != "" {
725				info.Description = pkg.Description
726			}
727			if pkg.Type != "" {
728				info.Type = string(pkg.Type)
729			}
730			if pkg.Source != "" {
731				info.RegistrySource = pkg.Source
732			}
733			if len(pkg.Keywords) > 0 {
734				info.Keywords = append([]string(nil), pkg.Keywords...)
735			}
736			if manifest, err := json.Marshal(pkg); err == nil {
737				info.Manifest = strPtr(string(manifest))
738			}
739		}
740		info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
741		info.Prompts = uniqueStrings(append(info.Prompts, scanNamedChildren(root, []string{"prompts", "library/prompts"}, "")...))
742		info.Templates = uniqueStrings(append(info.Templates, scanNamedChildren(root, []string{"templates", "library/templates"}, "")...))
743	}
744	
745	func dirSize(root string) int {
746		var total int64
747		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
748			if err != nil || d.IsDir() {
749				return nil
750			}
751			if info, err := d.Info(); err == nil {
752				total += info.Size()
753			}
754			return nil
755		})
756		const maxInt32 = int64(1<<31 - 1)
757		if total > maxInt32 {
758			return int(maxInt32)
759		}
760		return int(total)
761	}
762	
763	func scanNamedChildren(root string, relDirs []string, marker string) []string {
764		var out []string
765		for _, rel := range relDirs {
766			base := filepath.Join(root, filepath.FromSlash(rel))
767			entries, err := os.ReadDir(base)
768			if err != nil {
769				continue
770			}
771			for _, entry := range entries {
772				if strings.HasPrefix(entry.Name(), ".") {
773					continue
774				}
775				if marker != "" {
776					if !entry.IsDir() {
777						continue
778					}
779					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
780						continue
781					}
782				}
783				out = append(out, entry.Name())
784			}
785		}
786		return out
787	}
