804	func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
805		projectRoot := r.WorkingDir
806		if projectID != nil && strings.TrimSpace(*projectID) != "" {
807			projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
808		}
809		startedAfter, err := parseOptionalEfficacyTime("since", since)
810		if err != nil {
811			return efficacySnapshot{}, err
812		}
813		startedBefore, err := parseOptionalEfficacyTime("until", until)
