945				Harness:            parts[0],
946				Provider:           parts[1],
947				Model:              parts[2],
948				Attempts:           len(group),
949				Successes:          successes,
950				SuccessRate:        float64(successes) / float64(len(group)),
951				MedianInputTokens:  medianInt(inputTokens),
952				MedianOutputTokens: medianInt(outputTokens),
953				MedianDurationMs:   medianInt(durations),
